$.ajaxSetup({
    headers: {
        "X-CSRF-TOKEN": $('meta[name="csrf-token"]').attr("content"),
    },
});

$(function () {

    // Add User
    $(`form[action="{{ route('user.add') }}"]`).on("submit", function (e) {
        e.preventDefault();
        let form = $(this);

        $.ajax({
            url: form.attr("action"),
            type: "POST",
            data: form.serialize(),
            success: function (res) {
                if (res.success) {
                    $("#modalAdd").modal("hide");
                    table.ajax.reload();
                    Swal.fire("Sukses", res.message, "success");
                }
            },
            error: function (xhr) {
                Swal.fire(
                    "Error",
                    xhr.responseJSON.message || "Terjadi kesalahan",
                    "error"
                );
            },
        });
    });

    // Update User
    $(document).on(
        `submit', 'form[action^="{{ url('/admin/users') }}"]`,
        function (e) {
            e.preventDefault();
            let form = $(this);

            $.ajax({
                url: form.attr("action"),
                type: "POST", // tetap pakai POST karena ada _method PUT
                data: form.serialize(),
                success: function (res) {
                    if (res.success) {
                        form.closest(".modal").modal("hide");
                        table.ajax.reload();
                        Swal.fire("Sukses", res.message, "success");
                    }
                },
                error: function (xhr) {
                    Swal.fire(
                        "Error",
                        xhr.responseJSON.message || "Terjadi kesalahan",
                        "error"
                    );
                },
            });
        }
    );
});